async function (parametri = {
  user_prompt: '',
  system_prompt: '',
  modello: ''
}) {
  const user_prompt = parametri.user_prompt ?? '';
  const max_tokens = parametri.max_tokens ?? 8192;
  const temperature = parametri.temperature ?? 0.0;
  const system_prompt = parametri.system_prompt ?? '';
  if (!user_prompt) {
    return null;
  }
  const modello = parametri.modello || "google/gemini-2.5-flash-lite-preview-06-17";
  const messages = [];
  if (system_prompt) {
    messages.push({
      "role": "system",
      "content": system_prompt
    });
  }
  messages.push({
    "role": "user",
    "content": user_prompt
  });
  const request = {
    "model": modello,
    "max_tokens": max_tokens,
    "temperature": temperature,
    "messages": messages
  };
  await xcall.run({
    richiesta: request
  });
  return xcall.data;
}

