export default {
	tenants: [],
	accountingData:[] ,
	generaTenantIdList () {
		const tenantIds = getAnisettaTenants.data.map(tenant => tenant.as7_tenant_id);
		const idString = tenantIds.join(',');
		const url = `/orgUnits?where=type.eq('tenant').and(id.in(${idString})).and(name.ne('KlajdiandCo'))`;

		return url;
	},
	async listaTenants () {
		const URL = this.generaTenantIdList() ;
		await getTimooAPI.run({URL: URL});
		// this.tenants = getTimooAPI.data.orgUnits;
		return getTimooAPI.data;
	},
	async reportData () {
		const sourceData = await this.listaTenants(); 
		const tenantMap = {};
		sourceData.orgUnits.forEach(unit => {
			tenantMap[unit.id] = unit.name;
		});

		const statsData = await getUsersSEbyDay.run();
		const reportData = statsData.map(day => {
			return {
				...day,
				tenant_name: tenantMap[day.tenant_id] || "Unknown" // Aggiunge il nome o "Unknown" se non trovato
			};
		});
		this.accountingData = reportData;
		return reportData;

	}
}

